async function executeListMetaAreas(input, env3) {
  const res = await env3.KG_WORKER.fetch(
    `https://knowledge-graph-worker/getknowgraphsummaries?offset=0&limit=500`,
    { headers: { "x-user-role": "Superadmin" } }
  );
  if (!res.ok) throw new Error("Failed to fetch graph summaries");
  const data = await res.json();
  const metaAreaCounts = {};
  const categoryCounts = {};
  for (const g of data.results || []) {
    const meta3 = g.metadata || {};
    const rawMeta = meta3.metaArea || "";
    const areas = rawMeta.split("#").map((s2) => s2.trim().toUpperCase()).filter(Boolean);
    if (areas.length === 0 && rawMeta.trim()) {
      areas.push(rawMeta.trim().toUpperCase());
    }
    for (const area of areas) {
      metaAreaCounts[area] = (metaAreaCounts[area] || 0) + 1;
    }
    const rawCat = meta3.category || "";
    const cats = rawCat.split("#").map((s2) => s2.trim()).filter(Boolean);
    for (const cat of cats) {
      categoryCounts[cat] = (categoryCounts[cat] || 0) + 1;
    }
  }
  const metaAreas = Object.entries(metaAreaCounts).sort((a2, b) => b[1] - a2[1]).map(([name21, count3]) => ({ name: name21, count: count3 }));
  const categories = Object.entries(categoryCounts).sort((a2, b) => b[1] - a2[1]).map(([name21, count3]) => ({ name: name21, count: count3 }));
  return {
    message: `Found ${metaAreas.length} meta areas and ${categories.length} categories`,
    metaAreas,
    categories
  };
}
