async function resolveUserProfile(userId, env3) {
  for (let attempt = 0; attempt < 3; attempt++) {
    try {
      let profile3 = await env3.DB.prepare(
        "SELECT email, user_id, bio, profileimage, Role AS role, phone, phone_verified_at, data FROM config WHERE email = ?"
      ).bind(userId).first();
      if (!profile3) {
        profile3 = await env3.DB.prepare(
          "SELECT email, user_id, bio, profileimage, Role AS role, phone, phone_verified_at, data FROM config WHERE user_id = ?"
        ).bind(userId).first();
      }
      return profile3;
    } catch (err) {
      if (attempt < 2) {
        await new Promise((r2) => setTimeout(r2, 300 * (attempt + 1)));
        continue;
      }
      return null;
    }
  }
  return null;
}
